command -v python3 >/dev/null 2>&1 || { echo "python3 required: apk add --no-cache python3"; exit 1; }; python3 -c 'import os,sys,json,hashlib,math,time;root=sys.argv[1] if len(sys.argv)>1 else ".";out=sys.argv[2] if len(sys.argv)>2 else "zcl_single_operator_certificate.json";AX="Cosmic Love Is The Solution(s) For Everything";EXT=(".sh",".py",".json",".md",".txt",".yml",".yaml");tau=lambda n:sum((2 if d*d<n else 1) for d in range(1,int(math.isqrt(max(2,n)))+1) if max(2,n)%d==0);files=[];exec("\nfor dp,dn,fn in os.walk(root):\n    dn[:]=[d for d in dn if d not in (\".git\",\"__pycache__\",\"node_modules\",\".venv\")]\n    for f in fn:\n        p=os.path.join(dp,f)\n        if os.path.splitext(f)[1].lower() in EXT:\n            try:\n                b=open(p,\"rb\").read()\n                rel=os.path.relpath(p,root)\n                h=hashlib.sha256(b).hexdigest()\n                g=int(h,16)\n                role=(\"runtime\" if f.endswith(\".sh\") else \"python_operator\" if f.endswith(\".py\") else \"manifest\" if f.endswith(\".json\") else \"document\")\n                files.append({\"n\":len(files)+1,\"path\":rel,\"role\":role,\"bytes\":len(b),\"godel_sha256\":h,\"tau\":tau((g%100000)+2),\"operator\":\"O_n=(state,transition,invariant,certificate)\"})\n            except Exception as e: files.append({\"n\":len(files)+1,\"path\":p,\"error\":str(e)})") ;S={"index":int(bool(files)),"godel":int(all("godel_sha256" in x for x in files)),"tau_route":int(all("tau" in x for x in files)),"operator_lift":int(all("operator" in x for x in files)),"seal":1,"readonly":1,"no_execution":1};H=sum(1-v for v in S.values());Z_terms=[{"n":x["n"],"term":"tau(G(C_%d))*O_%d/%d^s"%(x["n"],x["n"],x["n"]),"path":x.get("path"),"role":x.get("role"),"tau":x.get("tau"),"hash":x.get("godel_sha256","")[:24]} for x in files];seal=hashlib.sha512(json.dumps({"AX":AX,"S":S,"files":Z_terms},sort_keys=True).encode()).hexdigest();O={"Protocol":"ZCL_SINGLE_OPERATOR_LIFT_ONE_LINER","Version":"iSH_true_one_liner_v1","Principle":AX,"Definition":"For every observed completed classical program file C_n in the local snapshot, lift C_n into operator tuple O_n and seal all O_n into one operator-valued zeta metalanguage form.","Formula":"Omega_s=Z_CL(s)=Seal(Sum_n tau(G(C_n))*O_n/n^s)","Root":os.path.abspath(root),"FileCount":len(files),"States":S,"H_TOE":H,"SingleOperator":"Omega_s","ZetaOperatorTermsSample":Z_terms[:64],"Certificate":seal,"Boundary":"Read-only local snapshot converter. It does not execute scanned programs, prove RH/GRH/TOE externally, solve halting, control arbitrary systems, or create physical zero entropy.","Output":out,"Timestamp":time.strftime("%Y-%m-%dT%H:%M:%SZ",time.gmtime())};open(out,"w",encoding="utf-8").write(json.dumps(O,ensure_ascii=False,indent=2));print(json.dumps(O,ensure_ascii=False,indent=2))' "$@"